  1	import * as React from 'react';
  2	import {
  3	  Alert,
  4	  Flex,
  5	  FlexItem,
  6	  PageSection,
  7	  PageSectionVariants,
  8	  Title,
  9	} from '@patternfly/react-core';
 10	import _ from 'lodash';
 11	import { useTranslation } from 'react-i18next';
 12	import { IncompleteDataError } from '@openshift-console/dynamic-plugin-sdk/lib/utils/error/http-error';
 13	import { EmptyBox } from '../empty-state/EmptyBox';
 14	import { AccessDenied } from '../empty-state/AccessDenied';
 15	import { LoadingBox } from '../loading/LoadingBox';
 16	import { LoadError } from '../loading/LoadError';
 17	import { getLastLanguage } from '../../../../utils/getLastLanguage';
 18	
 19	const Data: React.FC<DataProps> = ({
 20	  NoDataEmptyMsg,
 21	  EmptyMsg,
 22	  label,
 23	  data,
 24	  unfilteredData,
 25	  children,
 26	}) => {
 27	  if (NoDataEmptyMsg && _.isEmpty(unfilteredData)) {
 28	    return (
 29	      <div className="loading-box loading-box__loaded">
 30	        {NoDataEmptyMsg ? <NoDataEmptyMsg /> : <EmptyBox label={label} />}
 31	      </div>
 32	    );
 33	  }
 34	
 35	  if (!data || _.isEmpty(data)) {
 36	    return (
 37	      <div className="loading-box loading-box__loaded">
 38	        {EmptyMsg ? <EmptyMsg /> : <EmptyBox label={label} />}
 39	      </div>
 40	    );
 41	  }
 42	  return <div className="loading-box loading-box__loaded">{children}</div>;
 43	};
 44	Data.displayName = 'Data';
 45	
 46	export const StatusBox: React.FC<StatusBoxProps> = (props) => {
 47	  const { loadError, loaded, skeleton, data, ...dataProps } = props;
 48	  const { t } = useTranslation('console-shared');
 49	
 50	  if (loadError) {
 51	    const status = _.get(loadError, 'response.status');
 52	    if (status === 404) {
 53	      return (
 54	        <PageSection variant={PageSectionVariants.light}>
 55	          <Flex justifyContent={{ default: 'justifyContentCenter' }}>
 56	            <FlexItem>
 57	              <Title headingLevel="h1">{t('404: Not Found')}</Title>
 58	            </FlexItem>
 59	          </Flex>
 60	        </PageSection>
 61	      );
 62	    }
 63	    if (status === 403) {
 64	      return <AccessDenied>{loadError.message}</AccessDenied>;
 65	    }
 66	
 67	    if (loadError instanceof IncompleteDataError && !_.isEmpty(data)) {
 68	      return (
 69	        <Data data={data} {...dataProps}>
 70	          <Alert
 71	            variant="info"
 72	            isInline
 73	            title={t(
 74	              '{{labels}} content is not available in the catalog at this time due to loading failures.',
 75	              {
 76	                labels: new Intl.ListFormat(getLastLanguage() || 'en', {
 77	                  style: 'long',
 78	                  type: 'conjunction',
 79	                }).format(loadError.labels),
 80	              },
 81	            )}
 82	          />
 83	          {props.children}
 84	        </Data>
 85	      );
 86	    }
 87	
 88	    return <LoadError label={props.label}>{loadError.message}</LoadError>;
 89	  }
 90	
 91	  if (!loaded) {
 92	    return skeleton ? <>{skeleton}</> : <LoadingBox />;
 93	  }
 94	  return <Data data={data} {...dataProps} />;
 95	};
 96	StatusBox.displayName = 'StatusBox';
 97	
 98	type DataProps = {
 99	  NoDataEmptyMsg?: React.ComponentType;
100	  EmptyMsg?: React.ComponentType;
101	  label?: string;
102	  unfilteredData?: any;
103	  data?: any;
104	  children?: React.ReactNode;
105	};
106	
107	type StatusBoxProps = {
108	  label?: string;
109	  loadError?: any;
110	  loaded?: boolean;
111	  data?: any;
112	  unfilteredData?: any;
113	  skeleton?: React.ReactNode;
114	  NoDataEmptyMsg?: React.ComponentType;
115	  EmptyMsg?: React.ComponentType;
116	  children?: React.ReactNode;
117	};

